args:
set -eu
SYSTEM_CA_PRIMARY=/etc/ssl/certs/ca-certificates.crt
SYSTEM_CA_FALLBACK=/etc/ssl/cert.pem
CUSTOM_CA=/custom-ca/customCA.crt
OUTPUT=/combined-ca/ca-bundle.crt
if [ -f "$SYSTEM_CA_PRIMARY" ]; then
  cat "$SYSTEM_CA_PRIMARY" "$CUSTOM_CA" > "$OUTPUT";
elif [ -f "$SYSTEM_CA_FALLBACK" ]; then
  cat "$SYSTEM_CA_FALLBACK" "$CUSTOM_CA" > "$OUTPUT";
elif [ -f "$CUSTOM_CA" ]; then
  # Fall back to custom CA only when system CA bundle path differs.
  cat "$CUSTOM_CA" > "$OUTPUT";
else
  echo "custom CA file not found at $CUSTOM_CA" >&2;
  exit 1;
fi
